  1	import React, { ChangeEvent, FC } from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import {
  5	  FormGroup,
  6	  NumberInput,
  7	  SelectList,
  8	  Split,
  9	  SplitItem,
 10	  ValidatedOptions,
 11	} from '@patternfly/react-core';
 12	import { SelectOption } from '@patternfly/react-core';
 13	
 14	import FormGroupHelperText from '../FormGroupHelperText/FormGroupHelperText';
 15	import FormPFSelect from '../FormPFSelect/FormPFSelect';
 16	
 17	import { CAPACITY_UNITS, removeByteSuffix } from './utils';
 18	
 19	type CapacityInputProps = {
 20	  isEditingCreatedDisk?: boolean;
 21	  isMinusDisabled?: boolean;
 22	  label?: string;
 23	  onChange: (quantity: string) => void;
 24	  size: string;
 25	};
 26	
 27	const CapacityInput: FC<CapacityInputProps> = ({
 28	  isEditingCreatedDisk,
 29	  isMinusDisabled,
 30	  label,
 31	  onChange,
 32	  size,
 33	}) => {
 34	  const { t } = useKubevirtTranslation();
 35	  const [unitValue = ''] = size?.match(/[a-zA-Z]+/g) || [];
 36	  const [sizeValue = 0] = size?.match(/[0-9]+/g) || [];
 37	  const unit = !unitValue?.endsWith('B') ? `${unitValue}B` : unitValue;
 38	  const value = Number(sizeValue);
 39	
 40	  const onFormatChange = (_, newUnit: CAPACITY_UNITS) => {
 41	    onChange(`${Number(value)}${removeByteSuffix(newUnit)}`);
 42	  };
 43	  const unitOptions = Object.values(CAPACITY_UNITS);
 44	  if (!unitOptions?.includes(unit as CAPACITY_UNITS)) unitOptions.push(unit as CAPACITY_UNITS);
 45	
 46	  const validated: ValidatedOptions =
 47	    !value || value <= 0 ? ValidatedOptions.error : ValidatedOptions.default;
 48	
 49	  return (
 50	    <FormGroup
 51	      className="disk-source-form-group"
 52	      fieldId={`size-required`}
 53	      isRequired
 54	      label={label}
 55	    >
 56	      <Split hasGutter>
 57	        <SplitItem>
 58	          <NumberInput
 59	            onChange={(event: ChangeEvent<HTMLInputElement>) =>
 60	              Number(event?.target?.value) <= Number.MAX_SAFE_INTEGER &&
 61	              onChange(`${Number(event.target.value)}${removeByteSuffix(unit)}`)
 62	            }
 63	            onPlus={() =>
 64	              Number(value) < Number.MAX_SAFE_INTEGER &&
 65	              onChange(`${Number(value) + 1}${removeByteSuffix(unit)}`)
 66	            }
 67	            isDisabled={isEditingCreatedDisk}
 68	            max={Number.MAX_SAFE_INTEGER}
 69	            min={1}
 70	            minusBtnAriaLabel={t('Decrement')}
 71	            minusBtnProps={{ isDisabled: isMinusDisabled }}
 72	            onMinus={() => onChange(`${Number(value) - 1}${removeByteSuffix(unit)}`)}
 73	            plusBtnAriaLabel={t('Increment')}
 74	            value={value}
 75	          />
 76	        </SplitItem>
 77	        <SplitItem>
 78	          <FormPFSelect onSelect={onFormatChange} selected={unit}>
 79	            <SelectList>
 80	              {unitOptions.map((formatOption) => (
 81	                <SelectOption
 82	                  isDisabled={isEditingCreatedDisk}
 83	                  key={formatOption}
 84	                  value={formatOption}
 85	                >
 86	                  {formatOption}
 87	                </SelectOption>
 88	              ))}
 89	            </SelectList>
 90	          </FormPFSelect>
 91	        </SplitItem>
 92	      </Split>
 93	      <FormGroupHelperText validated={validated}>
 94	        {validated === ValidatedOptions.error &&
 95	          t('Size cannot be {{errorValue}}', {
 96	            errorValue: value < 0 ? 'negative' : 'zero',
 97	          })}
 98	      </FormGroupHelperText>
 99	    </FormGroup>
100	  );
101	};
102	
103	export default CapacityInput;

